//! Solution for https://leetcode.com/problems/maximum-score-from-grid-operations
//! 3225. Maximum Score From Grid Operations

impl Solution {
    pub fn maximum_score_(
        grid: &[Vec<i64>],
        col: usize,
        prev_prev: usize,
        prev: usize,
        n: usize,
        dp: &mut [Vec<Vec<Option<i64>>>],
    ) -> i64 {
        if col == n {
            0
        } else if let Some(val) = dp[col][prev][prev_prev] {
            val
        } else {
            let mut max = 0;
            for i in 0..=n {
                let val = if prev >= i {
                    grid[prev][col + 1] - grid[i][col + 1]
                } else if prev_prev < i {
                    grid[i][col] - grid[prev_prev.max(prev)][col]
                } else {
                    0
                };
                max = max.max(val + Self::maximum_score_(grid, col + 1, prev, i, n, dp))
            }
            dp[col][prev][prev_prev] = Some(max);
            max
        }
    }

    pub fn maximum_score(grid: Vec<Vec<i32>>) -> i64 {
        let n = grid.len();
        let mut new_grid = vec![vec![0; n + 1]; n + 1];
        let mut dp = vec![vec![vec![Option::<i64>::None; n + 1]; n + 1]; n + 1];
        for i in 0..n {
            let mut sum = 0;
            for j in 0..n {
                sum += grid[j][i] as i64;
                new_grid[j + 1][i + 1] = sum;
            }
        }
        std::mem::drop(grid);
        Self::maximum_score_(&new_grid, 0, 0, 0, n, &mut dp)
    }
}

